diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..99f220edefdd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1775,6 +1775,34 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     }
   }

+  // (add (lshr X, ShiftC), (zext (icmp ne (and X, MaskC), 0)))
+  //     -> (lshr (add X, MaskC), ShiftC)
+  // where MaskC = (1 << ShiftC) - 1. This is a ceiling division:
+  // ceil(X / 2^ShiftC) = floor((X + 2^ShiftC - 1) / 2^ShiftC)
+  Value *X;
+  const APInt *ShiftC, *MaskC;
+  if (match(&I, m_c_Add(
+          m_OneUse(m_LShr(m_Value(X), m_APInt(ShiftC))),
+          m_OneUse(m_ZExt(m_OneUse(m_SpecificICmp(
+              ICmpInst::ICMP_NE,
+              m_OneUse(m_And(m_Specific(X), m_APInt(MaskC))),
+              m_ZeroInt())))))) &&
+      *MaskC ==
+          (APInt(MaskC->getBitWidth(), 1) << ShiftC->getZExtValue()) - 1) {
+    // The transformation is valid only if X + MaskC does not overflow.
+    KnownBits Known = computeKnownBits(X, &I, /*Depth*/ 0);
+    unsigned LZ = Known.countMinLeadingZeros();
+    // X + MaskC does not overflow if the maximum possible value of X plus
+    // MaskC fits in the bit width.
+    APInt MaxX = APInt::getMaxValue(Known.getBitWidth()).lshr(LZ);
+    if (MaskC->ule(APInt::getMaxValue(Known.getBitWidth()) - MaxX)) {
+      Value *Add = Builder.CreateAdd(
+          X, ConstantInt::get(X->getType(), *MaskC), "", /*HasNUW*/ true,
+          /*HasNSW*/ true);
+      return BinaryOperator::CreateLShr(
+          Add, ConstantInt::get(X->getType(), *ShiftC));
+    }
+  }
   // (add (add A, 1), (sext (icmp ne A, 0))) => call umax(A, 1)
   if (match(LHS, m_Add(m_Value(A), m_One())) &&
       match(RHS, m_OneUse(m_SExt(m_OneUse(m_SpecificICmp(
@@ -1786,6 +1814,33 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {

   if (Instruction *Ashr = foldAddToAshr(I))
     return Ashr;
+  // Ceiling division by power-of-2:
+  // (X >> log2(N)) + zext(X & (N-1) != 0) --> (X + (N-1)) >> log2(N)
+  // This is valid when adding (N-1) to X doesn't overflow.
+  {
+    Value *X;
+    const APInt *ShiftAmt, *Mask;
+    CmpPredicate Pred;
+
+    // Match: (X >> C) + zext((X & Mask) != 0)
+    // or:    zext((X & Mask) != 0) + (X >> C)
+    if (match(&I, m_c_Add(m_OneUse(m_LShr(m_Value(X), m_APInt(ShiftAmt))),
+                          m_ZExt(m_SpecificICmp(
+                              ICmpInst::ICMP_NE,
+                              m_And(m_Deferred(X), m_LowBitMask(Mask)),
+                              m_ZeroInt())))) &&
+        Mask->popcount() == *ShiftAmt) {
+
+      // Check if X + Mask doesn't overflow
+      Constant *MaskC = ConstantInt::get(X->getType(), *Mask);
+      if (willNotOverflowUnsignedAdd(X, MaskC, I)) {
+        // (X + Mask) >> ShiftAmt
+        Value *Add = Builder.CreateNUWAdd(X, MaskC);
+        return BinaryOperator::CreateLShr(
+            Add, ConstantInt::get(X->getType(), *ShiftAmt));
+      }
+    }
+  }

   // (~X) + (~Y) --> -2 - (X + Y)
   {

